 125→
 126→    private final BlockingQueue<Command> queuedCommands = new PriorityBlockingQueue<>();
 127→    private final Set<MessagingListener> listeners = new CopyOnWriteArraySet<>();
 128→    private final ExecutorService threadPool = Executors.newCachedThreadPool();
 129→    private final MemorizingMessagingListener memorizingMessagingListener = new MemorizingMessagingListener();
 130→    private final DraftOperations draftOperations;
