 412→    public Future<?> searchRemoteMessages(String acctUuid, long folderId, String query, Set<Flag> requiredFlags,
 413→            Set<Flag> forbiddenFlags, MessagingListener listener) {
 414→        Timber.i("searchRemoteMessages (acct = %s, folderId = %d, query = %s)", acctUuid, folderId, query);
 415→
 416→        return threadPool.submit(() ->
 417→                searchRemoteMessagesSynchronous(acctUuid, folderId, query, requiredFlags, forbiddenFlags, listener)
 418→        );
