 421→    @VisibleForTesting
 422→    void searchRemoteMessagesSynchronous(String acctUuid, long folderId, String query, Set<Flag> requiredFlags,
 423→            Set<Flag> forbiddenFlags, MessagingListener listener) {
 424→
 425→        Account account = preferences.getAccount(acctUuid);
 426→
 427→        if (listener != null) {
 428→            listener.remoteSearchStarted(folderId);
 429→        }
 430→
 431→        List<String> extraResults = new ArrayList<>();
 432→        try {
 433→            LocalStore localStore = localStoreProvider.getInstance(account);
 434→
 435→            LocalFolder localFolder = localStore.getFolder(folderId);
 436→            if (!localFolder.exists()) {
 437→                throw new MessagingException("Folder not found");
 438→            }
 439→
 440→            localFolder.open();
 441→            String folderServerId = localFolder.getServerId();
 442→
 443→            Backend backend = getBackend(account);
 444→
 445→            boolean performFullTextSearch = account.isRemoteSearchFullText();
 446→            List<String> messageServerIds = backend.search(folderServerId, query, requiredFlags, forbiddenFlags,
 447→                    performFullTextSearch);
 448→
 449→            Timber.i("Remote search got %d results", messageServerIds.size());
 450→
 451→            // There's no need to fetch messages already completely downloaded
 452→            messageServerIds = localFolder.extractNewMessages(messageServerIds);
 453→
 454→            if (listener != null) {
 455→                listener.remoteSearchServerQueryComplete(folderId, messageServerIds.size(),
 456→                        account.getRemoteSearchNumResults());
 457→            }
 458→
 459→            int resultLimit = account.getRemoteSearchNumResults();
 460→            if (resultLimit > 0 && messageServerIds.size() > resultLimit) {
 461→                extraResults = messageServerIds.subList(resultLimit, messageServerIds.size());
 462→                messageServerIds = messageServerIds.subList(0, resultLimit);
 463→            }
 464→
 465→            loadSearchResultsSynchronous(account, messageServerIds, localFolder);
 466→        } catch (Exception e) {
 467→            if (Thread.currentThread().isInterrupted()) {
 468→                Timber.i(e, "Caught exception on aborted remote search; safe to ignore.");
 469→            } else {
 470→                Timber.e(e, "Could not complete remote search");
 471→                if (listener != null) {
 472→                    listener.remoteSearchFailed(null, e.getMessage());
 473→                }
 474→                Timber.e(e);
 475→            }
 476→        } finally {
 477→            if (listener != null) {
 478→                listener.remoteSearchFinished(folderId, 0, account.getRemoteSearchNumResults(), extraResults);
 479→            }
 480→        }
 481→
 482→    }
