 484→    public void loadSearchResults(Account account, long folderId, List<String> messageServerIds,
 485→            MessagingListener listener) {
 486→        threadPool.execute(() -> {
 487→            if (listener != null) {
 488→                listener.enableProgressIndicator(true);
 489→            }
 490→
 491→            try {
 492→                LocalStore localStore = localStoreProvider.getInstance(account);
 493→                LocalFolder localFolder = localStore.getFolder(folderId);
 494→                if (!localFolder.exists()) {
 495→                    throw new MessagingException("Folder not found");
 496→                }
 497→
 498→                localFolder.open();
 499→
 500→                loadSearchResultsSynchronous(account, messageServerIds, localFolder);
 501→            } catch (MessagingException e) {
 502→                Timber.e(e, "Exception in loadSearchResults");
 503→            } finally {
 504→                if (listener != null) {
 505→                    listener.enableProgressIndicator(false);
 506→                }
 507→            }
 508→        });
 509→    }
