 511→    private void loadSearchResultsSynchronous(Account account, List<String> messageServerIds, LocalFolder localFolder)
 512→            throws MessagingException {
 513→
 514→        Backend backend = getBackend(account);
 515→        String folderServerId = localFolder.getServerId();
 516→
 517→        for (String messageServerId : messageServerIds) {
 518→            LocalMessage localMessage = localFolder.getMessage(messageServerId);
 519→
 520→            if (localMessage == null) {
 521→                backend.downloadMessageStructure(folderServerId, messageServerId);
 522→            }
 523→        }
