 555→    public void synchronizeMailboxBlocking(Account account, String folderServerId) {
 556→        long folderId = getFolderId(account, folderServerId);
 557→
 558→        final CountDownLatch latch = new CountDownLatch(1);
 559→        putBackground("synchronizeMailbox", null, () -> {
 560→            try {
 561→                synchronizeMailboxSynchronous(account, folderId, true, null, new NotificationState());
 562→            } finally {
 563→                latch.countDown();
 564→            }
 565→        });
 566→
 567→        try {
 568→            latch.await();
 569→        } catch (Exception e) {
 570→            Timber.e(e, "Interrupted while awaiting latch release");
 571→        }
 572→    }
