 698→        putBackground("processPendingCommands", null, new Runnable() {
 699→            @Override
 700→            public void run() {
 701→                try {
 702→                    processPendingCommandsSynchronous(account);
 703→                } catch (MessagingException me) {
 704→                    Timber.e(me, "processPendingCommands");
 705→
 706→                    /*
