 715→    public void processPendingCommandsSynchronous(Account account) throws MessagingException {
 716→        LocalStore localStore = localStoreProvider.getInstance(account);
 717→        List<PendingCommand> commands = localStore.getPendingCommands();
 718→
 719→        PendingCommand processingCommand = null;
 720→        try {
 721→            for (PendingCommand command : commands) {
 722→                processingCommand = command;
 723→                String commandName = command.getCommandName();
 724→                Timber.d("Processing pending command '%s'", commandName);
 725→
 726→                /*
 727→                 * We specifically do not catch any exceptions here. If a command fails it is
 728→                 * most likely due to a server or IO error and it must be retried before any
 729→                 * other command processes. This maintains the order of the commands.
 730→                 */
 731→                try {
 732→                    command.execute(this, account);
 733→
 734→                    localStore.removePendingCommand(command);
 735→
 736→                    Timber.d("Done processing pending command '%s'", commandName);
 737→                } catch (MessagingException me) {
 738→                    if (me.isPermanentFailure()) {
 739→                        Timber.e(me, "Failure of command '%s' was permanent, removing command from queue", commandName);
 740→                        localStore.removePendingCommand(processingCommand);
 741→                    } else {
 742→                        throw me;
 743→                    }
 744→                } catch (Exception e) {
 745→                    Timber.e(e, "Unexpected exception with command '%s', removing command from queue", commandName);
 746→                    localStore.removePendingCommand(processingCommand);
 747→
 748→                    if (K9.DEVELOPER_MODE) {
 749→                        throw new AssertionError("Unexpected exception while processing pending command", e);
 750→                    }
 751→                }
 752→
 753→                // TODO: When removing a pending command due to an error the local changes should be reverted. Pending
 754→                //  commands that depend on this command should be canceled and local changes be reverted. In most cases
 755→                //  the user should be notified about the failure as well.
 756→            }
 757→        } catch (MessagingException me) {
 758→            notifyUserIfCertificateProblem(account, me, true);
 759→            Timber.e(me, "Could not process command '%s'", processingCommand);
 760→            throw me;
 761→        }
 762→    }
