 952→    void destroyPlaceholderMessages(LocalFolder localFolder, List<String> uids) throws MessagingException {
 953→        for (String uid : uids) {
 954→            LocalMessage placeholderMessage = localFolder.getMessage(uid);
 955→            if (placeholderMessage == null) {
 956→                continue;
 957→            }
 958→
 959→            if (placeholderMessage.isSet(Flag.DELETED)) {
 960→                placeholderMessage.destroy();
 961→            } else {
 962→                Timber.w("Expected local message %s in folder %s to be a placeholder, but DELETE flag wasn't set",
 963→                        uid, localFolder.getServerId());
 964→
 965→                if (BuildConfig.DEBUG) {
 966→                    throw new AssertionError("Placeholder message must have the DELETED flag set");
 967→                }
 968→            }
 969→        }
 970→    }
