1070→    private void setFlagSynchronous(final Account account, final List<Long> ids,
1071→            final Flag flag, final boolean newState, final boolean threadedList) {
1072→
1073→        LocalStore localStore;
1074→        try {
1075→            localStore = localStoreProvider.getInstance(account);
1076→        } catch (MessagingException e) {
1077→            Timber.e(e, "Couldn't get LocalStore instance");
1078→            return;
1079→        }
1080→
1081→        // Update affected messages in the database. This should be as fast as possible so the UI
1082→        // can be updated with the new state.
1083→        try {
1084→            if (threadedList) {
1085→                localStore.setFlagForThreads(ids, flag, newState);
1086→                removeFlagForThreadsFromCache(account, ids, flag);
1087→            } else {
1088→                localStore.setFlag(ids, flag, newState);
1089→                removeFlagFromCache(account, ids, flag);
1090→            }
1091→        } catch (MessagingException e) {
1092→            Timber.e(e, "Couldn't set flags in local database");
1093→        }
1094→
1095→        // Read folder ID and UID of messages from the database
1096→        Map<Long, List<String>> folderMap;
1097→        try {
1098→            folderMap = localStore.getFolderIdsAndUids(ids, threadedList);
1099→        } catch (MessagingException e) {
1100→            Timber.e(e, "Couldn't get folder name and UID of messages");
1101→            return;
1102→        }
1103→
1104→        boolean accountSupportsFlags = supportsFlags(account);
1105→
1106→        // Loop over all folders
1107→        for (Entry<Long, List<String>> entry : folderMap.entrySet()) {
1108→            long folderId = entry.getKey();
1109→            List<String> uids = entry.getValue();
1110→
1111→            // Notify listeners of changed folder status
1112→            for (MessagingListener l : getListeners()) {
1113→                l.folderStatusChanged(account, folderId);
1114→            }
1115→
1116→            if (flag == Flag.SEEN && newState) {
1117→                cancelNotificationsForMessages(account, folderId, uids);
1118→            }
1119→
1120→            if (accountSupportsFlags) {
1121→                LocalFolder localFolder = localStore.getFolder(folderId);
1122→                try {
1123→                    localFolder.open();
1124→                    if (!localFolder.isLocalOnly()) {
1125→                        // Send flag change to server
1126→                        queueSetFlag(account, folderId, newState, flag, uids);
1127→                        processPendingCommands(account);
1128→                    }
1129→                } catch (MessagingException e) {
1130→                    Timber.e(e, "Couldn't open folder. Account: %s, folder ID: %d", account, folderId);
1131→                }
1132→            }
1133→        }
1134→    }
