1220→            Backend backend = getBackend(account);
1221→
1222→            if (loadPartialFromSearch) {
1223→                SyncConfig syncConfig = createSyncConfig(account);
1224→                backend.downloadMessage(syncConfig, folderServerId, messageServerId);
1225→            } else {
1226→                backend.downloadCompleteMessage(folderServerId, messageServerId);
1227→            }
1228→
1229→            for (MessagingListener l : getListeners(listener)) {
1230→                l.loadMessageRemoteFinished(account, folderId, messageServerId);
1231→            }
1232→        } catch (Exception e) {
1233→            for (MessagingListener l : getListeners(listener)) {
1234→                l.loadMessageRemoteFailed(account, folderId, messageServerId, e);
1235→            }
1236→
1237→            notifyUserIfCertificateProblem(account, e, true);
