1604→    private void moveOrDeleteSentMessage(Account account, LocalStore localStore, LocalMessage message)
1605→            throws MessagingException {
1606→        if (!account.hasSentFolder() || !account.isUploadSentMessages()) {
1607→            Timber.i("Not uploading sent message; deleting local message");
1608→            message.destroy();
1609→        } else {
1610→            long sentFolderId = account.getSentFolderId();
1611→            LocalFolder sentFolder = localStore.getFolder(sentFolderId);
1612→            sentFolder.open();
1613→            String sentFolderServerId = sentFolder.getServerId();
1614→            Timber.i("Moving sent message to folder '%s' (%d)", sentFolderServerId, sentFolderId);
1615→
1616→            MessageStore messageStore = messageStoreManager.getMessageStore(account);
1617→            long destinationMessageId = messageStore.moveMessage(message.getDatabaseId(), sentFolderId);
1618→
1619→            Timber.i("Moved sent message to folder '%s' (%d)", sentFolderServerId, sentFolderId);
1620→
1621→            if (!sentFolder.isLocalOnly()) {
1622→                String destinationUid = messageStore.getMessageServerId(destinationMessageId);
1623→                if (destinationUid != null) {
1624→                    PendingCommand command = PendingAppend.create(sentFolderId, destinationUid);
1625→                    queuePendingCommand(account, command);
1626→                    processPendingCommands(account);
1627→                }
1628→            }
1629→        }
1630→
1631→        for (MessagingListener listener : getListeners()) {
1632→            listener.folderStatusChanged(account, account.getOutboxFolderId());
1633→        }
1634→    }
