2065→                        queueDelete(account, folderId, syncedMessageUids);
2066→                    } else if (account.isMarkMessageAsReadOnDelete()) {
2067→                        queueMoveOrCopy(account, folderId, trashFolderId,
2068→                                MoveOrCopyFlavor.MOVE_AND_MARK_AS_READ, uidMap);
2069→                    } else {
2070→                        queueMoveOrCopy(account, folderId, trashFolderId,
2071→                                MoveOrCopyFlavor.MOVE, uidMap);
2072→                    }
2073→                    processPendingCommands(account);
2074→                } else if (account.getDeletePolicy() == DeletePolicy.MARK_AS_READ) {
2075→                    queueSetFlag(account, localFolder.getDatabaseId(), true, Flag.SEEN, syncedMessageUids);
2076→                    processPendingCommands(account);
2077→                } else {
2078→                    Timber.d("Delete policy %s prevents delete from server", account.getDeletePolicy());
2079→                }
2080→            }
2081→
2082→            unsuppressMessages(account, messages);
2083→        } catch (MessagingException me) {
2084→            throw new RuntimeException("Error deleting message from local store.", me);
2085→        }
2086→    }
