316→            String[] values = context.getResources().getStringArray(resId);
317→            for (String value : values) {
318→                int intValue = Integer.parseInt(value);
319→                mapping.put(intValue, value);
320→            }
321→            this.mapping = Collections.unmodifiableMap(mapping);
322→        }
