 21→class NotificationActionService : Service() {
 22→    private val preferences: Preferences by inject()
 23→    private val messagingController: MessagingController by inject()
 24→    private val coroutineScope: CoroutineScope by inject(named("AppCoroutineScope"))
 25→
 26→    override fun onStartCommand(intent: Intent, flags: Int, startId: Int): Int {
 27→        Timber.i("NotificationActionService started with startId = %d", startId)
 28→
 29→        startHandleCommand(intent, startId)
 30→
 31→        return START_NOT_STICKY
 32→    }
 33→
 34→    private fun startHandleCommand(intent: Intent, startId: Int) {
 35→        coroutineScope.launch(Dispatchers.IO) {
 36→            handleCommand(intent)
 37→            stopSelf(startId)
 38→        }
 39→    }
 40→
 41→    private fun handleCommand(intent: Intent) {
 42→        val accountUuid = intent.getStringExtra(EXTRA_ACCOUNT_UUID)
 43→        if (accountUuid == null) {
 44→            Timber.w("Missing account UUID.")
 45→            return
 46→        }
 47→
 48→        val account = preferences.getAccount(accountUuid)
 49→        if (account == null) {
 50→            Timber.w("Could not find account for notification action.")
 51→            return
 52→        }
 53→
 54→        when (intent.action) {
 55→            ACTION_MARK_AS_READ -> markMessagesAsRead(intent, account)
 56→            ACTION_DELETE -> deleteMessages(intent)
 57→            ACTION_ARCHIVE -> archiveMessages(intent)
 58→            ACTION_SPAM -> markMessageAsSpam(intent, account)
 59→            ACTION_DISMISS -> Timber.i("Notification dismissed")
 60→        }
 61→
 62→        cancelNotifications(intent, account)
 63→    }
 64→
 65→    override fun onBind(intent: Intent): IBinder? {
 66→        return null
 67→    }
 68→
 69→    private fun markMessagesAsRead(intent: Intent, account: Account) {
 70→        Timber.i("NotificationActionService marking messages as read")
 71→
 72→        val messageReferenceStrings = intent.getStringArrayListExtra(EXTRA_MESSAGE_REFERENCES)
 73→        val messageReferences = MessageReferenceHelper.toMessageReferenceList(messageReferenceStrings)
 74→
 75→        for (messageReference in messageReferences) {
 76→            val folderId = messageReference.folderId
 77→            val uid = messageReference.uid
 78→            messagingController.setFlag(account, folderId, uid, Flag.SEEN, true)
 79→        }
 80→    }
 81→
 82→    private fun deleteMessages(intent: Intent) {
 83→        Timber.i("NotificationActionService deleting messages")
 84→
 85→        val messageReferenceStrings = intent.getStringArrayListExtra(EXTRA_MESSAGE_REFERENCES)
 86→        val messageReferences = MessageReferenceHelper.toMessageReferenceList(messageReferenceStrings)
 87→
 88→        messagingController.deleteMessages(messageReferences)
 89→    }
 90→
 91→    private fun archiveMessages(intent: Intent) {
 92→        Timber.i("NotificationActionService archiving messages")
 93→
 94→        val messageReferenceStrings = intent.getStringArrayListExtra(EXTRA_MESSAGE_REFERENCES)
 95→        val messageReferences = MessageReferenceHelper.toMessageReferenceList(messageReferenceStrings)
 96→
 97→        messagingController.archiveMessages(messageReferences)
 98→    }
 99→
100→    private fun markMessageAsSpam(intent: Intent, account: Account) {
101→        Timber.i("NotificationActionService moving messages to spam")
102→
103→        val messageReferenceString = intent.getStringExtra(EXTRA_MESSAGE_REFERENCE)
104→        val messageReference = MessageReference.parse(messageReferenceString)
105→
106→        if (messageReference == null) {
107→            Timber.w("Invalid message reference: %s", messageReferenceString)
108→            return
109→        }
110→
111→        val spamFolderId = account.spamFolderId
112→        if (spamFolderId == null) {
113→            Timber.w("No spam folder configured")
114→            return
115→        }
116→
117→        if (!K9.isConfirmSpam && messagingController.isMoveCapable(account)) {
118→            val sourceFolderId = messageReference.folderId
119→            messagingController.moveMessage(account, sourceFolderId, messageReference, spamFolderId)
120→        }
121→    }
122→
123→    private fun cancelNotifications(intent: Intent, account: Account) {
124→        if (intent.hasExtra(EXTRA_MESSAGE_REFERENCE)) {
125→            val messageReferenceString = intent.getStringExtra(EXTRA_MESSAGE_REFERENCE)
126→            val messageReference = MessageReference.parse(messageReferenceString)
127→
128→            if (messageReference != null) {
129→                messagingController.cancelNotificationForMessage(account, messageReference)
130→            } else {
131→                Timber.w("Invalid message reference: %s", messageReferenceString)
132→            }
133→        } else if (intent.hasExtra(EXTRA_MESSAGE_REFERENCES)) {
134→            val messageReferenceStrings = intent.getStringArrayListExtra(EXTRA_MESSAGE_REFERENCES)
135→            val messageReferences = MessageReferenceHelper.toMessageReferenceList(messageReferenceStrings)
136→
137→            for (messageReference in messageReferences) {
138→                messagingController.cancelNotificationForMessage(account, messageReference)
139→            }
140→        } else {
141→            messagingController.cancelNotificationsForAccount(account)
142→        }
143→    }
