        `when`(messagingController.actOnMessagesGroupedByAccountAndFolder(any(), any())).thenAnswer { invocation ->
            val actor = invocation.getArgument<MessagingController.MessageActor>(1)
            actor.act(account, localFolder, listOf(localMessage))
        }
    }

    @Test
    fun archiveMessages_shouldUseMoveAndMarkAsRead() {
        val messageReference = MessageReference("account-uuid", 1L, "msg-uid")

        archiveOperations.archiveMessages(listOf(messageReference))

        verify(messagingController).moveOrCopyMessageSynchronous(
            eq(account),
            eq(1L),
            eq(listOf(localMessage)),
            eq(100L),
            eq(MoveOrCopyFlavor.MOVE_AND_MARK_AS_READ)
        )
    }
}
