 582→    private void refreshFolderListIfStale(Account account) {
 583→        long lastFolderListRefresh = account.getLastFolderListRefreshTime();
 584→        long now = System.currentTimeMillis();
 585→
 586→        if (lastFolderListRefresh > now || lastFolderListRefresh + FOLDER_LIST_STALENESS_THRESHOLD <= now) {
 587→            Timber.d("Last folder list refresh @ %tc. Refreshing now…", lastFolderListRefresh);
 588→            refreshFolderListSynchronous(account);
 589→        } else {
 590→            Timber.d("Last folder list refresh @ %tc. Not refreshing now.", lastFolderListRefresh);
 591→        }
