 594→    private void syncFolder(Account account, long folderId, boolean notify, MessagingListener listener, Backend backend,
 595→            NotificationState notificationState) {
 596→        if (isAuthenticationProblem(account, true)) {
 597→            Timber.d("Authentication will fail. Skip synchronizing folder %d.", folderId);
 598→            handleAuthenticationFailure(account, true);
 599→            return;
 600→        }
 601→
 602→        Exception commandException = null;
 603→        try {
 604→            processPendingCommandsSynchronous(account);
 605→        } catch (Exception e) {
 606→            Timber.e(e, "Failure processing command, but allow message sync attempt");
 607→            commandException = e;
 608→        }
 609→
 610→        LocalFolder localFolder;
 611→        try {
 612→            LocalStore localStore = localStoreProvider.getInstance(account);
 613→            localFolder = localStore.getFolder(folderId);
 614→            localFolder.open();
 615→        } catch (MessagingException e) {
 616→            Timber.e(e, "syncFolder: Couldn't load local folder %d", folderId);
 617→            return;
 618→        }
 619→
 620→        // We can't sync local folders
 621→        if (localFolder.isLocalOnly()) {
 622→            return;
 623→        }
 624→
 625→        final boolean suppressNotifications;
 626→        if (notify) {
 627→            MessageStore messageStore = messageStoreManager.getMessageStore(account);
 628→            Long lastChecked = messageStore.getFolder(folderId, FolderDetailsAccessor::getLastChecked);
 629→            suppressNotifications = lastChecked == null;
 630→        } else {
 631→            suppressNotifications = true;
 632→        }
 633→
 634→        String folderServerId = localFolder.getServerId();
 635→        SyncConfig syncConfig = createSyncConfig(account);
 636→        ControllerSyncListener syncListener =
 637→                new ControllerSyncListener(account, listener, suppressNotifications, notificationState);
 638→
 639→        backend.sync(folderServerId, syncConfig, syncListener);
 640→
 641→        if (commandException != null && !syncListener.syncFailed) {
 642→            String rootMessage = getRootCauseMessage(commandException);
 643→            Timber.e("Root cause failure in %s:%s was '%s'", account, folderServerId, rootMessage);
 644→            updateFolderStatus(account, folderId, rootMessage);
 645→            listener.synchronizeMailboxFailed(account, folderId, rootMessage);
 646→        }
 647→    }
