 764→    /**
 765→     * Process a pending append message command. This command uploads a local message to the
 766→     * server, first checking to be sure that the server message is not newer than
 767→     * the local message. Once the local message is successfully processed it is deleted so
 768→     * that the server message will be synchronized down without an additional copy being
 769→     * created.
 770→     */
 771→    void processPendingAppend(PendingAppend command, Account account) throws MessagingException {
 772→        LocalStore localStore = localStoreProvider.getInstance(account);
 773→        long folderId = command.folderId;
 774→        LocalFolder localFolder = localStore.getFolder(folderId);
 775→        localFolder.open();
 776→
 777→        String folderServerId = localFolder.getServerId();
 778→        String uid = command.uid;
 779→
 780→        LocalMessage localMessage = localFolder.getMessage(uid);
 781→        if (localMessage == null) {
 782→            return;
 783→        }
 784→
 785→        if (!localMessage.getUid().startsWith(K9.LOCAL_UID_PREFIX)) {
 786→            //FIXME: This should never happen. Throw in debug builds.
 787→            return;
 788→        }
 789→
 790→        Backend backend = getBackend(account);
 791→
 792→        if (localMessage.isSet(Flag.X_REMOTE_COPY_STARTED)) {
 793→            Timber.w("Local message with uid %s has flag %s  already set, checking for remote message with " +
 794→                    "same message id", localMessage.getUid(), X_REMOTE_COPY_STARTED);
 795→
 796→            String messageServerId = backend.findByMessageId(folderServerId, localMessage.getMessageId());
 797→            if (messageServerId != null) {
 798→                Timber.w("Local message has flag %s already set, and there is a remote message with uid %s, " +
 799→                        "assuming message was already copied and aborting this copy",
 800→                        X_REMOTE_COPY_STARTED, messageServerId);
 801→
 802→                String oldUid = localMessage.getUid();
 803→                localMessage.setUid(messageServerId);
 804→                localFolder.changeUid(localMessage);
 805→
 806→                for (MessagingListener l : getListeners()) {
 807→                    l.messageUidChanged(account, folderId, oldUid, localMessage.getUid());
 808→                }
 809→
 810→                return;
 811→            } else {
 812→                Timber.w("No remote message with message-id found, proceeding with append");
 813→            }
 814→        }
 815→
 816→        /*
 817→         * If the message does not exist remotely we just upload it and then
 818→         * update our local copy with the new uid.
 819→         */
 820→        FetchProfile fp = new FetchProfile();
 821→        fp.add(FetchProfile.Item.BODY);
 822→        localFolder.fetch(Collections.singletonList(localMessage), fp, null);
 823→        String oldUid = localMessage.getUid();
 824→        localMessage.setFlag(Flag.X_REMOTE_COPY_STARTED, true);
 825→
 826→        String messageServerId = backend.uploadMessage(folderServerId, localMessage);
 827→
 828→        if (messageServerId == null) {
 829→            // We didn't get the server UID of the uploaded message. Remove the local message now. The uploaded
 830→            // version will be downloaded during the next sync.
 831→            localFolder.destroyMessages(Collections.singletonList(localMessage));
 832→        } else {
 833→            localMessage.setUid(messageServerId);
 834→            localFolder.changeUid(localMessage);
 835→
 836→            for (MessagingListener l : getListeners()) {
 837→                l.messageUidChanged(account, folderId, oldUid, localMessage.getUid());
 838→            }
 839→        }
 840→    }
