 886→    @VisibleForTesting
 887→    void processPendingMoveOrCopy(Account account, long srcFolderId, long destFolderId, List<String> uids,
 888→                                  MoveOrCopyFlavor operation, Map<String, String> newUidMap) throws MessagingException {
 889→        requireNotNull(newUidMap);
 890→
 891→        LocalStore localStore = localStoreProvider.getInstance(account);
 892→
 893→        LocalFolder localSourceFolder = localStore.getFolder(srcFolderId);
 894→        localSourceFolder.open();
 895→        String srcFolderServerId = localSourceFolder.getServerId();
 896→
 897→        LocalFolder localDestFolder = localStore.getFolder(destFolderId);
 898→        localDestFolder.open();
 899→        String destFolderServerId = localDestFolder.getServerId();
 900→
 901→        Backend backend = getBackend(account);
 902→
 903→        Map<String, String> remoteUidMap;
 904→        switch (operation) {
 905→            case COPY:
 906→                remoteUidMap = backend.copyMessages(srcFolderServerId, destFolderServerId, uids);
 907→                break;
 908→            case MOVE:
 909→                remoteUidMap = backend.moveMessages(srcFolderServerId, destFolderServerId, uids);
 910→                break;
 911→            case MOVE_AND_MARK_AS_READ:
 912→                remoteUidMap = backend.moveMessagesAndMarkAsRead(srcFolderServerId, destFolderServerId, uids);
 913→                break;
 914→            default:
 915→                throw new RuntimeException("Unsupported messaging operation");
 916→        }
 917→
 918→        if (operation != MoveOrCopyFlavor.COPY) {
 919→            destroyPlaceholderMessages(localSourceFolder, uids);
 920→        }
 921→
 922→        // TODO: Change Backend interface to ensure we never receive null for remoteUidMap
 923→        if (remoteUidMap == null) {
 924→            remoteUidMap = Collections.emptyMap();
 925→        }
 926→
 927→        // Update local messages (that currently have local UIDs) with new server IDs
 928→        for (String uid : uids) {
 929→            String localUid = newUidMap.get(uid);
 930→            String newUid = remoteUidMap.get(uid);
 931→
 932→            LocalMessage localMessage = localDestFolder.getMessage(localUid);
 933→            if (localMessage == null) {
 934→                // Local message no longer exists
 935→                continue;
 936→            }
 937→
 938→            if (newUid != null) {
 939→                // Update local message with new server ID
 940→                localMessage.setUid(newUid);
 941→                localDestFolder.changeUid(localMessage);
 942→                for (MessagingListener l : getListeners()) {
 943→                    l.messageUidChanged(account, destFolderId, localUid, newUid);
 944→                }
 945→            } else {
 946→                // New server ID wasn't provided. Remove local message.
 947→                localMessage.destroy();
 948→            }
 949→        }
 950→    }
