1206→    private void loadMessageRemoteSynchronous(Account account, long folderId, String messageServerId,
1207→            MessagingListener listener, boolean loadPartialFromSearch) {
1208→        try {
1209→            if (messageServerId.startsWith(K9.LOCAL_UID_PREFIX)) {
1210→                throw new IllegalArgumentException("Must not be called with a local UID");
1211→            }
1212→
1213→            MessageStore messageStore = messageStoreManager.getMessageStore(account);
1214→
1215→            String folderServerId = messageStore.getFolderServerId(folderId);
1216→            if (folderServerId == null) {
1217→                throw new IllegalStateException("Folder not found (ID: " + folderId + ")");
1218→            }
1219→
1220→            Backend backend = getBackend(account);
1221→
1222→            if (loadPartialFromSearch) {
1223→                SyncConfig syncConfig = createSyncConfig(account);
1224→                backend.downloadMessage(syncConfig, folderServerId, messageServerId);
1225→            } else {
1226→                backend.downloadCompleteMessage(folderServerId, messageServerId);
