1278→    public void markMessageAsOpened(Account account, LocalMessage message) {
1279→        threadPool.execute(() ->
1280→            notificationController.removeNewMailNotification(account, message.makeMessageReference())
1281→        );
1282→
1283→        if (message.isSet(Flag.SEEN)) {
1284→            // Nothing to do if the message is already marked as read
1285→            return;
1286→        }
1287→
1288→        boolean markMessageAsRead = account.isMarkMessageAsReadOnView();
1289→        if (markMessageAsRead) {
1290→            // Mark the message itself as read right away
1291→            try {
1292→                message.setFlagInternal(Flag.SEEN, true);
1293→            } catch (MessagingException e) {
1294→                Timber.e(e, "Error while marking message as read");
1295→            }
1296→
1297→            // Also mark the message as read in the cache
1298→            List<Long> messageIds = Collections.singletonList(message.getDatabaseId());
1299→            setFlagInCache(account, messageIds, Flag.SEEN, true);
1300→        }
1301→
1302→        putBackground("markMessageAsOpened", null, () -> {
1303→            markMessageAsOpenedBlocking(account, message, markMessageAsRead);
1304→        });
1305→    }
