1462→    /**
1463→     * Attempt to send any messages that are sitting in the Outbox.
1464→     */
1465→    @VisibleForTesting
1466→    protected void sendPendingMessagesSynchronous(final Account account) {
1467→        Exception lastFailure = null;
1468→        try {
1469→            if (isAuthenticationProblem(account, false)) {
1470→                Timber.d("Authentication will fail. Skip sending messages.");
1471→                handleAuthenticationFailure(account, false);
1472→                return;
1473→            }
1474→
1475→            LocalStore localStore = localStoreProvider.getInstance(account);
1476→            OutboxStateRepository outboxStateRepository = localStore.getOutboxStateRepository();
1477→            LocalFolder localFolder = localStore.getFolder(account.getOutboxFolderId());
1478→            if (!localFolder.exists()) {
1479→                Timber.w("Outbox does not exist");
1480→                return;
1481→            }
1482→
1483→            localFolder.open();
1484→
1485→            long outboxFolderId = localFolder.getDatabaseId();
1486→
1487→            List<LocalMessage> localMessages = localFolder.getMessages();
1488→            int progress = 0;
1489→            int todo = localMessages.size();
1490→            for (MessagingListener l : getListeners()) {
1491→                l.synchronizeMailboxProgress(account, outboxFolderId, progress, todo);
1492→            }
1493→            /*
1494→             * The profile we will use to pull all of the content
1495→             * for a given local message into memory for sending.
1496→             */
1497→            FetchProfile fp = new FetchProfile();
1498→            fp.add(FetchProfile.Item.ENVELOPE);
1499→            fp.add(FetchProfile.Item.BODY);
1500→
1501→            Timber.i("Scanning Outbox folder for messages to send");
1502→
1503→            Backend backend = getBackend(account);
1504→
1505→            for (LocalMessage message : localMessages) {
1506→                if (message.isSet(Flag.DELETED)) {
1507→                    //FIXME: When uploading a message to the remote Sent folder the move code creates a placeholder
1508→                    // message in the Outbox. This code gets rid of these messages. It'd be preferable if the
1509→                    // placeholder message was never created, though.
1510→                    message.destroy();
1511→                    continue;
1512→                }
1513→                try {
1514→                    long messageId = message.getDatabaseId();
1515→                    OutboxState outboxState = outboxStateRepository.getOutboxState(messageId);
1516→
1517→                    SendState sendState = outboxState.getSendState();
1518→                    if (sendState != SendState.READY) {
1519→                        Timber.v("Skipping sending message %s (reason: %s - %s)", message.getUid(),
1520→                                sendState.getDatabaseName(), outboxState.getSendError());
1521→
1522→                        if (sendState == SendState.RETRIES_EXCEEDED) {
1523→                            lastFailure = new MessagingException("Retries exceeded", true);
1524→                        } else {
1525→                            lastFailure = new MessagingException(outboxState.getSendError(), true);
1526→                        }
1527→                        continue;
1528→                    }
1529→
1530→                    Timber.i("Send count for message %s is %d", message.getUid(),
1531→                            outboxState.getNumberOfSendAttempts());
1532→
1533→                    localFolder.fetch(Collections.singletonList(message), fp, null);
1534→                    try {
1535→                        if (message.getHeader(K9.IDENTITY_HEADER).length > 0 || message.isSet(Flag.DRAFT)) {
1536→                            Timber.v("The user has set the Outbox and Drafts folder to the same thing. " +
1537→                                    "This message appears to be a draft, so K-9 will not send it");
1538→                            continue;
1539→                        }
1540→
1541→                        outboxStateRepository.incrementSendAttempts(messageId);
1542→                        message.setFlag(Flag.X_SEND_IN_PROGRESS, true);
1543→
1544→                        Timber.i("Sending message with UID %s", message.getUid());
1545→                        backend.sendMessage(message);
1546→
1547→                        message.setFlag(Flag.X_SEND_IN_PROGRESS, false);
1548→                        message.setFlag(Flag.SEEN, true);
1549→                        progress++;
1550→                        for (MessagingListener l : getListeners()) {
1551→                            l.synchronizeMailboxProgress(account, outboxFolderId, progress, todo);
1552→                        }
1553→                        moveOrDeleteSentMessage(account, localStore, message);
1554→
1555→                        outboxStateRepository.removeOutboxState(messageId);
1556→                    } catch (AuthenticationFailedException e) {
1557→                        outboxStateRepository.decrementSendAttempts(messageId);
1558→                        lastFailure = e;
1559→
1560→                        handleAuthenticationFailure(account, false);
1561→                        handleSendFailure(account, localFolder, message, e);
1562→                    } catch (CertificateValidationException e) {
1563→                        outboxStateRepository.decrementSendAttempts(messageId);
1564→                        lastFailure = e;
1565→
1566→                        notifyUserIfCertificateProblem(account, e, false);
1567→                        handleSendFailure(account, localFolder, message, e);
1568→                    } catch (MessagingException e) {
1569→                        lastFailure = e;
1570→
1571→                        if (e.isPermanentFailure()) {
1572→                            String errorMessage = e.getMessage();
1573→                            outboxStateRepository.setSendAttemptError(messageId, errorMessage);
1574→                        } else if (outboxState.getNumberOfSendAttempts() + 1 >= MAX_SEND_ATTEMPTS) {
1575→                            outboxStateRepository.setSendAttemptsExceeded(messageId);
1576→                        }
1577→
1578→                        handleSendFailure(account, localFolder, message, e);
1579→                    } catch (Exception e) {
1580→                        lastFailure = e;
1581→
1582→                        handleSendFailure(account, localFolder, message, e);
1583→                    }
1584→                } catch (Exception e) {
1585→                    lastFailure = e;
1586→
1587→                    Timber.e(e, "Failed to fetch message for sending");
1588→                    notifySynchronizeMailboxFailed(account, localFolder, e);
1589→                }
1590→            }
1591→
1592→            if (lastFailure != null) {
1593→                notificationController.showSendFailedNotification(account, lastFailure);
1594→            }
1595→        } catch (Exception e) {
1596→            Timber.v(e, "Failed to send pending messages");
1597→        } finally {
1598→            if (lastFailure == null) {
1599→                notificationController.clearSendFailedNotification(account);
1600→            }
1601→        }
1602→    }
