1753→    void moveOrCopyMessageSynchronous(Account account, long srcFolderId, List<LocalMessage> inMessages,
1754→            long destFolderId, MoveOrCopyFlavor operation) {
1755→
1756→        if (operation == MoveOrCopyFlavor.MOVE_AND_MARK_AS_READ) {
1757→            throw new UnsupportedOperationException("MOVE_AND_MARK_AS_READ unsupported");
1758→        }
1759→
1760→        try {
1761→            LocalStore localStore = localStoreProvider.getInstance(account);
1762→            if (operation == MoveOrCopyFlavor.MOVE && !isMoveCapable(account)) {
1763→                return;
1764→            }
1765→            if (operation == MoveOrCopyFlavor.COPY && !isCopyCapable(account)) {
1766→                return;
1767→            }
1768→
1769→            LocalFolder localSrcFolder = localStore.getFolder(srcFolderId);
1770→            localSrcFolder.open();
1771→
1772→            LocalFolder localDestFolder = localStore.getFolder(destFolderId);
1773→            localDestFolder.open();
1774→
1775→            boolean unreadCountAffected = false;
1776→            List<String> uids = new LinkedList<>();
1777→            for (Message message : inMessages) {
1778→                String uid = message.getUid();
1779→                if (!uid.startsWith(K9.LOCAL_UID_PREFIX)) {
1780→                    uids.add(uid);
1781→                }
1782→
1783→                if (!unreadCountAffected && !message.isSet(Flag.SEEN)) {
1784→                    unreadCountAffected = true;
1785→                }
1786→            }
1787→
1788→            List<LocalMessage> messages = localSrcFolder.getMessagesByUids(uids);
1789→            if (messages.size() > 0) {
1790→                Timber.i("moveOrCopyMessageSynchronous: source folder = %s, %d messages, destination folder = %s, " +
1791→                        "operation = %s", srcFolderId, messages.size(), destFolderId, operation.name());
1792→
1793→                MessageStore messageStore = messageStoreManager.getMessageStore(account);
1794→
1795→                List<Long> messageIds = new ArrayList<>();
1796→                Map<Long, String> messageIdToUidMapping = new HashMap<>();
1797→                for (LocalMessage message : messages) {
1798→                    long messageId = message.getDatabaseId();
1799→                    messageIds.add(messageId);
1800→                    messageIdToUidMapping.put(messageId, message.getUid());
1801→                }
1802→
1803→                Map<Long, Long> resultIdMapping;
1804→                if (operation == MoveOrCopyFlavor.COPY) {
1805→                    resultIdMapping = messageStore.copyMessages(messageIds, destFolderId);
1806→
1807→                    if (unreadCountAffected) {
1808→                        // If this copy operation changes the unread count in the destination
1809→                        // folder, notify the listeners.
1810→                        for (MessagingListener l : getListeners()) {
