308→    private static class IntegerResourceSetting extends PseudoEnumSetting<Integer> {
309→        private final Context context = DI.get(Context.class);
310→        private final Map<Integer, String> mapping;
311→
312→        IntegerResourceSetting(int defaultValue, int resId) {
313→            super(defaultValue);
314→
315→            Map<Integer, String> mapping = new HashMap<>();
316→            String[] values = context.getResources().getStringArray(resId);
317→            for (String value : values) {
318→                int intValue = Integer.parseInt(value);
319→                mapping.put(intValue, value);
320→            }
321→            this.mapping = Collections.unmodifiableMap(mapping);
322→        }
323→
324→        @Override
325→        protected Map<Integer, String> getMapping() {
326→            return mapping;
327→        }
328→
329→        @Override
330→        public Integer fromString(String value) throws InvalidSettingValueException {
331→            try {
332→                return Integer.parseInt(value);
333→            } catch (NumberFormatException e) {
334→                throw new InvalidSettingValueException();
335→            }
336→        }
337→    }
