292→                ContentValues cv = new ContentValues();
293→                cv.put("deleted", 1);
294→                cv.put("preview_type", DatabasePreviewType.fromPreviewType(PreviewType.NONE).getDatabaseValue());
295→                cv.put("read", 0);
296→                cv.put("flagged", 0);
297→                cv.put("answered", 0);
298→                cv.put("forwarded", 0);
299→                cv.putNull("subject");
300→                cv.putNull("sender_list");
301→                cv.putNull("date");
302→                cv.putNull("to_list");
303→                cv.putNull("cc_list");
304→                cv.putNull("bcc_list");
305→                cv.putNull("preview");
306→                cv.putNull("reply_to_list");
307→                cv.putNull("message_part_id");
308→                cv.putNull("flags");
309→                cv.putNull("attachment_count");
310→                cv.putNull("internal_date");
311→                cv.putNull("mime_type");
312→                cv.putNull("encryption_type");
313→
314→                db.update("messages", cv, "id = ?", new String[] { Long.toString(databaseId) });
315→
316→                mFolder.deleteMessagePartsAndDataFromDisk(messagePartId);
317→
318→                getFolder().deleteFulltextIndexEntry(db, databaseId);
319→
320→                return null;
321→            }
322→        });
323→
324→        localStore.notifyChange();
325→    }
